var data = $input.first().json;
if (!data.renderUrl) throw new Error('Missing renderUrl from Creatomate assembly');
return [{
  json: {
    videoId: data.videoId,
    outputPath: data.renderUrl,
    renderUrl: data.renderUrl,
    renderId: data.renderId,
    titulo: data.titulo,
    descricao: data.descricao,
    hashtags: data.hashtags,
    narracao: data.narracao,
    topic: data.topic,
    sceneCount: data.sceneCount,
    status: 'ready_to_publish'
  }
}];

var fs = require('fs');
var data = $input.first().json;
var videoId = data.videoId;

var outputDir = '/home/node/.n8n/output/' + videoId;
fs.mkdirSync(outputDir, { recursive: true });

var metadata = {
  videoId: videoId,
  titulo: data.titulo,
  descricao: data.descricao,
  hashtags: data.hashtags,
  outputPath: data.outputPath,
  publishResults: data.publishResults || null,
  platforms: data.platforms || [],
  publishedAt: data.publishedAt || null,
  savedAt: new Date().toISOString(),
  status: data.status || 'completed'
};

var metaPath = outputDir + '/metadata.json';
fs.writeFileSync(metaPath, JSON.stringify(metadata, null, 2));

return [{
  json: {
    videoId: videoId,
    metadataPath: metaPath,
    status: 'saved'
  }
}];

var items = $input.all();
var count = items.length;
var videoIds = items.map(function(item) { return item.json.videoId; }).filter(Boolean);

return [{
  json: {
    batchComplete: true,
    totalVideosProcessed: count,
    videoIds: videoIds,
    completedAt: new Date().toISOString(),
    message: 'Batch done: ' + count + ' video(s) processed'
  }
}];

var response = $input.first();
var cfg = $node['Set Config'].json;

var candidates = response.json.candidates;
var text = (candidates && candidates[0] && candidates[0].content && candidates[0].content.parts && candidates[0].content.parts[0])
  ? candidates[0].content.parts[0].text : '';

if (!text) throw new Error('Gemini returned no topics content');

var clean = text.replace(/```json/g, '').replace(/```/g, '').trim();

var topics;
try {
  topics = JSON.parse(clean);
} catch(e) {
  var match = clean.match(/\[[\s\S]*\]/);
  if (match) { topics = JSON.parse(match[0]); }
  else throw new Error('Invalid JSON from Gemini: ' + clean.substring(0, 200));
}

if (!Array.isArray(topics)) throw new Error('Not an array: ' + typeof topics);
if (topics.length === 0) throw new Error('Gemini returned 0 topics. Verifique o prompt.');

var runId = cfg.RUN_ID || new Date().toISOString().replace(/[^0-9]/g, '').substring(0, 14);

return topics.map(function(topic, i) {
  return {
    json: {
      milagre_de_jesus:  topic.milagre_de_jesus,
      versiculo_base:    topic.versiculo_base,
      gancho_inicial:    topic.gancho_inicial,
      palavras_chave:    topic.palavras_chave,
      categoria:         topic.categoria,
      runId:             runId,
      topicIndex:        i + 1,
      videoId:           runId + '_video_' + String(i + 1).padStart(2, '0'),
      GOOGLE_AI_API_KEY: cfg.GOOGLE_AI_API_KEY || '',
      ELEVENLABS_API_KEY: cfg.ELEVENLABS_API_KEY || ''
    }
  };
});

var childProcess = require('child_process');
var fs2 = require('fs');
var https2 = require('https');
var http2 = require('http');

var allItems = $input.all().map(function(i) { return i.json; });
var imageData = allItems.find(function(d) { return d.scenes && d.scenes.length > 0; }) || {};
var audioData = allItems.find(function(d) { return d.audioUrl; }) || {};

var videoId = imageData.videoId || audioData.videoId;
var audioUrl = audioData.audioUrl;
if (!audioUrl) throw new Error('No audioUrl for ' + videoId);

// Content fields come from audioData (repassed by Confirm Audio Ready)
var titulo    = audioData.titulo    || imageData.titulo    || '';
var descricao = audioData.descricao || imageData.descricao || '';
var hashtags  = audioData.hashtags  || imageData.hashtags  || [];
var narracao  = audioData.narracao  || imageData.narracao  || '';
var topic     = audioData.topic     || imageData.topic     || {};
var ctaText   = audioData.ctaText   || 'Siga e Compartilhe!';

var scenes = (imageData.scenes || [])
  .filter(function(s) { return s.url; })
  .sort(function(a, b) { return (a.numero || 0) - (b.numero || 0); });
if (!scenes.length) throw new Error('No scene URLs for ' + videoId);

var tempDir = '/home/node/.n8n/temp/' + videoId;
fs2.mkdirSync(tempDir, { recursive: true });

function download(fileUrl, destPath) {
  return new Promise(function(resolve, reject) {
    var mod = fileUrl.startsWith('https:') ? https2 : http2;
    var file = fs2.createWriteStream(destPath);
    mod.get(fileUrl, { rejectUnauthorized: false }, function(res) {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        file.close(); fs2.unlinkSync(destPath);
        return download(res.headers.location, destPath).then(resolve).catch(reject);
      }
      res.pipe(file);
      file.on('finish', function() { file.close(resolve); });
      res.on('error', reject);
    }).on('error', function(err) { fs2.unlink(destPath, function(){}); reject(err); });
  });
}

// Font (cached globally)
var fontPath = '/home/node/.n8n/temp/Roboto-Bold.ttf';
if (!fs2.existsSync(fontPath)) {
  await download('https://github.com/google/fonts/raw/main/apache/roboto/static/Roboto-Bold.ttf', fontPath);
}

// Download narration
var audioFile = tempDir + '/narration.mp3';
await download(audioUrl, audioFile);

// Measure real audio duration now — needed to size CTA correctly
var audioDurRaw = childProcess.execSync(
  'ffprobe -v quiet -show_entries format=duration -of csv=p=0 "' + audioFile + '"'
).toString().trim();
var audioDuration = parseFloat(audioDurRaw) || 30;

// Download background music
var MUSIC_TRACKS = [
  'https://cdn.pixabay.com/audio/2022/12/13/audio_a7e11a169f.mp3',
  'https://cdn.pixabay.com/audio/2024/05/28/audio_5bbbca17bf.mp3'
];
var musicFile = tempDir + '/music.mp3';
await download(MUSIC_TRACKS[Math.floor(Math.random() * MUSIC_TRACKS.length)], musicFile);

// Download scene videos
var sceneFiles = [];
for (var i = 0; i < scenes.length; i++) {
  var sceneFile = tempDir + '/scene_' + String(i + 1).padStart(2, '0') + '.mp4';
  await download(scenes[i].url, sceneFile);
  sceneFiles.push(sceneFile);
}

// ── Step 1: CTA clip ──────────────────────────────────────────────────────────
// Source: scene 3 (ACAO_JESUS — most divine visual, avoids repeating scene 4)
// Duration: audio remainder after 4×6s scenes, min 6s → eliminates loop artifact
var scenesDuration = scenes.length * 6; // 24s
var ctaDuration = Math.max(Math.ceil(audioDuration - scenesDuration), 6);
var ctaSource = sceneFiles[Math.min(2, sceneFiles.length - 1)]; // scene 3 (index 2)
var ctaRaw = tempDir + '/cta_raw.mp4';
childProcess.execSync(
  'ffmpeg -y -i "' + ctaSource + '" -t ' + ctaDuration +
  ' -c:v libx264 -preset ultrafast -an "' + ctaRaw + '"',
  { timeout: 60000 }
);

// ── Step 2: Concat 4 scenes + CTA → full_concat.mp4 ─────────────────────────
// Re-encode to ensure codec/resolution consistency (1080×1920)
var allFiles = sceneFiles.concat([ctaRaw]);
var concatList = tempDir + '/concat_full.txt';
fs2.writeFileSync(concatList, allFiles.map(function(f) { return "file '" + f + "'"; }).join('\n'));
var fullConcat = tempDir + '/full_concat.mp4';
childProcess.execSync(
  'ffmpeg -y -f concat -safe 0 -i "' + concatList + '"' +
  ' -c:v libx264 -preset veryfast -crf 23' +
  ' -vf scale=1080:1920:flags=lanczos' +
  ' -an "' + fullConcat + '"',
  { timeout: 300000 }
);

// ── Drawtext helpers ──────────────────────────────────────────────────────────
function escapeDrawtext(str) {
  return (str || '')
    .replace(/['"]/g, '')
    .replace(/:/g,   '')
    .replace(/[\[\]]/g, '')
    .replace(/%/g,   '')
    .replace(/,/g,   ' ')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

// Subtitles: 4 words/line, timing proportional to real audio duration
function buildSubtitleFilters(text, fontP, dur) {
  if (!text) return [];
  var words = text.trim().split(/\s+/);
  var grpSize = 4;
  var groups = [];
  for (var i = 0; i < words.length; i += grpSize) {
    groups.push(words.slice(i, i + grpSize).join(' '));
  }
  var perGroup = dur / groups.length;
  return groups.map(function(group, idx) {
    var start = (idx * perGroup).toFixed(2);
    var end   = Math.min((idx + 1) * perGroup, dur).toFixed(2);
    return (
      'drawtext=fontfile=' + fontP +
      ':text=\'' + escapeDrawtext(group) + '\'' +
      ':fontsize=56:fontcolor=white' +
      ':bordercolor=black@1.0:borderw=5' +
      ':x=(w-text_w)/2:y=h-200' +
      ':enable=\'between(t,' + start + ',' + end + ')\''
    );
  });
}

// CTA text overlay: 2 lines, centered, box only when text is valid
function buildCtaFilters(text, fontP, startTime) {
  var cleaned = (text || '').trim();
  if (!cleaned) return [];
  var words = cleaned.split(/\s+/);
  var mid   = Math.ceil(words.length / 2);
  var line1 = escapeDrawtext(words.slice(0, mid).join(' '));
  var line2 = escapeDrawtext(words.slice(mid).join(' '));
  var en    = 'gte(t,' + startTime + ')';
  var out   = [];
  if (line1) out.push(
    'drawtext=fontfile=' + fontP +
    ':text=\'' + line1 + '\'' +
    ':fontsize=58:fontcolor=white' +
    ':bordercolor=black@1.0:borderw=5' +
    ':box=1:boxcolor=black@0.75:boxborderw=14' +
    ':x=(w-text_w)/2:y=(h/2)-45' +
    ':enable=\'' + en + '\''
  );
  if (line2) out.push(
    'drawtext=fontfile=' + fontP +
    ':text=\'' + line2 + '\'' +
    ':fontsize=58:fontcolor=white' +
    ':bordercolor=black@1.0:borderw=5' +
    ':box=1:boxcolor=black@0.75:boxborderw=14' +
    ':x=(w-text_w)/2:y=(h/2)+30' +
    ':enable=\'' + en + '\''
  );
  return out;
}

// ── Step 3: Final assembly ───────────────────────────────────────────────────
var allVfFilters = buildSubtitleFilters(narracao, fontPath, audioDuration)
  .concat(buildCtaFilters(ctaText, fontPath, scenesDuration));
var vfChain = allVfFilters.length > 0 ? allVfFilters.join(',') : 'null';

var filterComplex =
  '[0:v]' + vfChain + '[v];' +
  '[1:a]volume=1.0[narr];' +
  '[2:a]volume=0.20[mus];' +
  '[narr][mus]amix=inputs=2:duration=first[aout]';

var finalVideo = tempDir + '/final.mp4';
// Note: NO stream_loop — full_concat duration ≈ audioDuration, no loop needed
childProcess.execSync(
  'ffmpeg -y' +
  ' -i "' + fullConcat + '"' +
  ' -i "' + audioFile + '"' +
  ' -stream_loop -1 -i "' + musicFile + '"' +
  ' -filter_complex "' + filterComplex + '"' +
  ' -map "[v]" -map "[aout]"' +
  ' -c:v libx264 -preset veryfast -crf 25' +
  ' -c:a aac -b:a 128k -shortest' +
  ' "' + finalVideo + '"',
  { timeout: 300000 }
);

var fileBuffer = fs2.readFileSync(finalVideo);

return [{
  json: {
    videoId: videoId,
    localPath: finalVideo,
    titulo: titulo,
    descricao: descricao,
    hashtags: hashtags,
    narracao: narracao,
    topic: topic,
    sceneCount: scenes.length,
    fileName: videoId + '.mp4'
  },
  binary: {
    data: {
      data: fileBuffer.toString('base64'),
      mimeType: 'video/mp4',
      fileName: videoId + '.mp4',
      fileExtension: 'mp4'
    }
  }
}];

var ffmpegData = $('FFmpeg: Assemble Video').first().json;
var uploadData = $('Drive: Upload Final Video').first().json;
var fileId = uploadData.id;
var renderUrl = 'https://drive.google.com/uc?export=download&id=' + fileId;
return [{
  json: {
    videoId: ffmpegData.videoId,
    renderUrl: renderUrl,
    renderId: fileId,
    sceneCount: ffmpegData.sceneCount,
    titulo: ffmpegData.titulo,
    descricao: ffmpegData.descricao,
    hashtags: ffmpegData.hashtags,
    narracao: ffmpegData.narracao,
    topic: ffmpegData.topic,
    status: 'assembled'
  }
}];

// Pega config do Set Config
const cfg = $node['Set Config'].json;

// Coleta todos os temas já registrados na planilha
const allItems = $input.all();
const temasUsados = allItems
  .map(item => item.json['Tema'] || item.json['tema'] || '')
  .filter(t => String(t).trim().length > 0);

const temasUsadosStr = temasUsados.length > 0
  ? '\n\nTEMAS JÁ PRODUZIDOS (NÃO REPITA NENHUM DESTES):\n'
    + temasUsados.map((t, i) => (i + 1) + '. ' + t).join('\n')
  : '';

return [{ json: { ...cfg, temasUsados, temasUsadosStr } }];

